INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Machine Shoulder (Military) Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Sit down on the Shoulder Press Machine and select the weight.','Grab the handles to your sides as you keep the elbows bent and in line with your torso. This will be your starting position.','Now lift the handles as you exhale and you extend the arms fully. At the top of the position make sure that you hold the contraction for a second.','Lower the handles slowly back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Machine Triceps Extension', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Adjust the seat to the appropriate height and make your weight selection. Place your upper arms against the pads and grasp the handles. This will be your starting position.','Perform the movement by extending the elbow, pulling your lower arm away from your upper arm.','Pause at the completion of the movement, and then slowly return the weight to the starting position.','Avoid returning the weight all the way to the stops until the set is complete to keep tension on the muscles being worked.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Medicine Ball Chest Pass', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['You will need a partner for this exercise. Lacking one, this movement can be performed against a wall.','Begin facing your partner holding the medicine ball at your torso with both hands.','Pull the ball to your chest, and reverse the motion by extending through the elbows. For sports applications, you can take a step as you throw.','Your partner should catch the ball, and throw it back to you.','Receive the throw with both hands at chest height.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Medicine Ball Full Twist', 'medicine ball', true, 'medicine ball', 'beginner', 'pull', 'compound', ARRAY['For this exercise you will need a medicine ball and a partner. Stand back to back with your partner, spaced 2-3 feet apart. This will be your starting position.','Hold the ball in front of the trunk. Open the hips and turn the shoulders at the same time as your partner.','For full rotation, you and your partner should twist in the same direction, i.e. counter-clockwise.','Pass the ball to your partner, and both of you can now twist in the opposite direction to repeat the procedure.'], ARRAY['abdominals'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Medicine Ball Scoop Throw', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['Assume a semisquat stance with a medicine ball in your hands. Your arms should hang so the ball is near your feet.','Begin by thrusting the hips forward as you extend through the legs, jumping up.','As you do, swing your arms up and over your head, keeping them extended, releasing the ball at the peak of your movement. The goal is to throw the ball the greatest distance behind you.'], ARRAY['shoulders'], ARRAY['abdominals','hamstrings','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Middle Back Shrug', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['Lie facedown on an incline bench while holding a dumbbell in each hand. Your arms should be fully extended hanging down and pointing towards the floor. The palms of your hands should be facing each other. This will be your starting position.','As you exhale, squeeze your shoulder blades together and hold the contraction for a full second. Tip: This movement is just like the reverse action of a hug, or trying to perform rear laterals as if you had no arms.','As you inhale go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Mixed Grip Chin', 'other', true, 'other', 'expert', 'pull', 'compound', ARRAY['Using a spacing that is just about 1 inch wider than shoulder width, grab a pull-up bar with the palms of one hand facing forward and the palms of the other hand facing towards you. This will be your starting position.','Now start to pull yourself up as you exhale. Tip: With the arm that has the palms facing up concentrate on using the back muscles in order to perform the movement. The elbow of that arm should remain close to the torso. With the other arm that has the palms facing forward, the elbows will be away but in line with the torso. You will concentrate on using the lats to pull your body up.','After a second contraction at the top, start to slowly come down as you inhale.','Repeat for the recommended amount of repetitions.','On the following set, switch grips; so if you had the right hand with the palms facing you and the left one with the palms facing forward, on the next set you will have the palms facing forward for the right hand and facing you for the left.'], ARRAY['middle back'], ARRAY['biceps','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Monster Walk', 'bands', true, 'bands', 'beginner', 'pull', 'compound', ARRAY['Place a band around both ankles and another around both knees. There should be enough tension that they are tight when your feet are shoulder width apart.','To begin, take short steps forward alternating your left and right foot.','After several steps, do just the opposite and walk backward to where you started.'], ARRAY['abductors'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Mountain Climbers', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Begin in a pushup position, with your weight supported by your hands and toes. Flexing the knee and hip, bring one leg until the knee is approximately under the hip. This will be your starting position.','Explosively reverse the positions of your legs, extending the bent leg until the leg is straight and supported by the toe, and bringing the other foot up with the hip and knee flexed. Repeat in an alternating fashion for 20-30 seconds.'], ARRAY['quadriceps'], ARRAY['chest','hamstrings','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Moving Claw Series', 'body only', true, 'body only', 'beginner', NULL, 'compound', ARRAY['This move helps prepare your running form to help you excel at sprinting. As you run, be sure to flex the knee, aiming to kick your glutes as the hip extends.','Reload the quad as the leg moves back forward, attacking the ground on the next step.','Ensure that as you run, you block with the arms, punching through in a rapid 1-2 motion.'], ARRAY['hamstrings'], ARRAY['calves','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Muscle Snatch', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin with a loaded barbell held at the mid thigh position with a wide grip. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.','Begin the pull by driving through the front of the heels, raising the bar. Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body.','Continue raising the bar to the overhead position, without rebending the knees.'], ARRAY['hamstrings'], ARRAY['glutes','lower back','quadriceps','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Muscle Up', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['Grip the rings using a false grip, with the base of your palms on top of the rings. Initiate a pull up by pulling the elbows down to your side, flexing the elbows.','As you reach the top position of the pull-up, pull the rings to your armpits as you roll your shoulders forward, allowing your elbows to move straight back behind you. This puts you into the proper position to continue into the dip portion of the movement.','Maintaining control and stability, extend through the elbow to complete the motion.','Use care when lowering yourself to the ground.'], ARRAY['lats'], ARRAY['abdominals','biceps','forearms','middle back','shoulders','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Narrow Stance Hack Squats', 'machine', true, 'machine', 'intermediate', 'push', 'compound', ARRAY['Place the back of your torso against the back pad of the machine and hook your shoulders under the shoulder pads provided.','Position your legs in the platform using a less than shoulder width narrow stance with the toes slightly pointed out. Your feet should be around 3 inches or less apart. Tip: Keep your head up at all times and also maintain the back on the pad at all times.','Place your arms on the side handles of the machine and disengage the safety bars (which on most designs is done by moving the side handles from a facing front position to a diagonal position).','Now straighten your legs without locking the knees. This will be your starting position.','Begin to slowly lower the unit by bending the knees as you maintain a straight posture with the head up (back on the pad at all times). Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement.','Begin to raise the unit as you exhale by pushing the floor with mainly with the heels of your feet as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Narrow Stance Leg Press', 'machine', true, 'machine', 'intermediate', 'push', 'compound', ARRAY['Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a less-than-shoulder-width narrow stance with the toes slightly pointed out. Your feet should be around 3 inches or less apart. Tip: Keep your head up at all times and also maintain the back on the pad at all times.','Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you. Tip: Make sure that you do not lock your knees. Your torso and the legs should make a perfect 90-degree angle. This will be your starting position.','As you inhale, slowly lower the platform until your upper and lower legs make a 90-degree angle.','Pushing mainly with the heels of your feet and using the quadriceps go back to the starting position as you exhale.','Repeat for the recommended amount of repetitions and ensure to lock the safety pins properly once you are done. You do not want that platform falling on you fully loaded.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Narrow Stance Squats', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a less-than-shoulder-width narrow stance with the toes slightly pointed out. Feet should be around 3-6 inches apart. Keep your head up at all times (looking down will get you off balance) and maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section).','Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Natural Glute Ham Raise', 'body only', true, 'body only', 'intermediate', 'pull', 'compound', ARRAY['Using the leg pad of a lat pulldown machine or a preacher bench, position yourself so that your ankles are under the pads, knees on the seat, and you are facing away from the machine. You should be upright and maintaining good posture.','This will be your starting position. Lower yourself under control until your knees are almost completely straight.','Remaining in control, raise yourself back up to the starting position.','If you are unable to complete a rep, use a band, a partner, or push off of a box to aid in completing a repetition.'], ARRAY['hamstrings'], ARRAY['calves','glutes','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Neck Press', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Lie back on a flat bench. Using a medium-width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over your neck with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your neck.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up).','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Oblique Crunches', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put one hand beside your head and the other to the side against the floor.','Make sure your feet are elevated and resting on a flat surface.','Now lift the shoulder in which your hand is touching your head.','Simply elevate your shoulder and body upward until you touch your knee. For example, if you have your right hand besides your head, then you want to elevate your body upwards until your right elbow touches your left knee. The same variation can be applied doing the inverse and using your left elbow to touch your right knee.','After your knee touches your elbow, lower your body until you have reached the starting position.','Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (upward) part of the exercise.','Continue alternating in this manner until all of the recommended repetitions for each side have been completed.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Oblique Crunches - On The Floor', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Start out by lying on your right side with your legs lying on top of each other. Make sure your knees are bent a little bit.','Place your left hand behind your head.','Once you are in this set position, begin by moving your left elbow up as you would perform a normal crunch except this time the main emphasis is on your obliques.','Crunch as high as you can, hold the contraction for a second and then slowly drop back down into the starting position.','Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (elevation) part of the exercise.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Olympic Squat', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin with a barbell supported on top of the traps. The chest should be up, and the head facing forward. Adopt a hip width stance with the feet turned out as needed.','Descend by flexing the knees, refraining from moving the hips back as much as possible. This requires that the knees travel forward; ensure that they stay aligned with the feet. The goal is to keep the torso as upright as possible. Continue all the way down, keeping the weight on the front of the heel.','At the moment the upper legs contact the lower, reverse the motion, driving the weight upward.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Dumbbell Row', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Choose a flat bench and place a dumbbell on each side of it.','Place the right leg on top of the end of the bench, bend your torso forward from the waist until your upper body is parallel to the floor, and place your right hand on the other end of the bench for support.','Use the left hand to pick up the dumbbell on the floor and hold the weight while keeping your lower back straight. The palm of the hand should be facing your torso. This will be your starting position.','Pull the resistance straight up to the side of your chest, keeping your upper arm close to your side and keeping the torso stationary. Breathe out as you perform this step. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. Also, make sure that the force is performed with the back muscles and not the arms. Finally, the upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the dumbbell; therefore do not try to pull the dumbbell up using the forearms.','Lower the resistance straight down to the starting position. Breathe in as you perform this step.','Repeat the movement for the specified amount of repetitions.','Switch sides and repeat again with the other arm.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'], ARRAY['Opposite hand and knee on bench','Pull dumbbell to hip, not to chest','Elbow drives straight back past body','Squeeze lat hard at top for 1 second','Let shoulder blade move, dont keep it locked'], ARRAY['Twisting torso to heave weight up','Pulling to armpit instead of hip','Rushing reps without squeezing'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Flat Bench Dumbbell Flye', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Lie down on a flat bench with a dumbbell in one hand resting on top of your thigh. The palm of your hand with the dumbbell in it should be at a neutral grip.','By using your thighs to help you get the dumbbell up, clean the dumbbell so that you can hold it in front of you with your lifting arm being fully extended. Remember to maintain a neutral grip with this exercise. Your non lifting hand should be to the side holding the flat bench for better support. This will be your starting position.','Your arm with the weight should have a slight bend on your elbow in order to prevent stress at the biceps tendon. Begin by lowering your arm with the weight in it out in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, your lifting arm should remain stationary; the movement should only occur at the shoulder joint.','Return your lifting arm back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.','Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions.','Switch arms and repeat the exercise.'], ARRAY['chest'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm High-Pulley Cable Side Bends', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Connect a standard handle to a tower. Move cable to highest pulley position.','Stand with side to cable. With one hand, reach up and grab handle with underhand grip.','Pull down cable until elbow touches your side and the handle is by your shoulder.','Position feet hip-width apart. Place free hand on hip to help gauge pivot point.','Keep arm in static position. Contract oblique to bring the weight down in a side crunch.','Once you reach maximum contraction, slowly release the weight to the starting position. The weight stack should never be unloaded in a resting position. The aim is constant tension during the set.','Repeat to failure.','Then, reposition and repeat the same series of movements on the opposite side.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Incline Lateral Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Lie down sideways on an incline bench press with a dumbbell in the hand. Make sure the shoulder is pressing against the incline bench and the arm is lying across your body with the palm around your navel.','Hold a dumbbell in your uppermost arm while keeping it extended in front of you parallel to the floor. This is your starting position.','While keeping the dumbbell parallel to the floor at all times, perform a lateral raise. Your arm should travel straight up until it is pointing at the ceiling. Tip: Exhale as you perform this movement. Hold the dumbbell in the position and feel the contraction in the shoulders for a second.','While inhaling lower the weight across your body back into the starting position.','Repeat the movement for the prescribed amount of repetitions.','Switch arms and repeat the movement.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Clean', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY['Place a kettlebell between your feet. As you bend down to grab the kettlebell, push your butt back and keep your eyes looking forward.','Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.','Return the weight to the starting position.'], ARRAY['hamstrings'], ARRAY['glutes','lower back','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Clean and Jerk', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Hold a kettlebell by the handle.','Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight.','Receive the weight overhead by returning to a squat position underneath the weight.','Keeping the weight overhead, return to a standing position. Lower the weight to the floor to perform the next repetition.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Floor Press', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Lie on the floor holding a kettlebell with one hand, with your upper arm supported by the floor. The palm should be facing in.','Press the kettlebell straight up toward the ceiling, rotating your wrist.','Lower the kettlebell back to the starting position and repeat.'], ARRAY['chest'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Jerk', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight. Receive the weight overhead by returning to a squat position underneath the weight. Keeping the weight overhead, return to a standing position.','Lower the weight to perform the next repetition.'], ARRAY['shoulders'], ARRAY['calves','quadriceps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Military Press To The Side', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces inward. This will be your starting position.','Look at the kettlebell and press it up and out until it is locked out overhead.','Lower the kettlebell back to your shoulder under control and repeat. Make sure to contract your lat, butt, and stomach forcefully for added stability and strength.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Para Press', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.','Hold the kettlebell with the elbow out to the side, and press it up and out until it is locked out overhead.','Lower the kettlebell back to your shoulder under control and repeat. Make sure to contract your lat, butt, and stomach forcefully for added stability and strength.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Push Press', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight. Lower the weight to perform the next repetition.'], ARRAY['shoulders'], ARRAY['calves','quadriceps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Row', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY['Place a kettlebell in front of your feet. Bend your knees slightly and then push your butt out as much as possible as you bend over to get in the starting position. Grab the kettlebell and pull it to your stomach, retracting your shoulder blade and flexing the elbow. Keep your back straight. Lower and repeat.'], ARRAY['middle back'], ARRAY['biceps','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Snatch', 'kettlebells', true, 'kettlebells', 'expert', 'pull', 'compound', ARRAY['Place a kettlebell between your feet. Bend your knees and push your butt back to get in the proper starting position.','Look straight ahead and swing the kettlebell back between your legs.','Immediately reverse the direction and drive through with your hips and knees, accelerating the kettlebell upward. As the kettlebell rises to your shoulder rotate your hand and punch straight up, using momentum to receive the weight locked out overhead.'], ARRAY['shoulders'], ARRAY['calves','glutes','hamstrings','lower back','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Split Jerk', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight.','Receive the weight overhead by returning to a squat position underneath the weight, positioning one leg in front of you and one leg behind you.','Keeping the weight overhead, return to a standing position and bring your feet together. Lower the weight to perform the next repetition.'], ARRAY['shoulders'], ARRAY['glutes','hamstrings','quadriceps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Split Snatch', 'kettlebells', true, 'kettlebells', 'expert', 'pull', 'compound', ARRAY['Hold a kettlebell in one hand by the handle.','Squat towards the floor, and then reverse the motion, extending the hips, knees, and finally the ankles, to raise the kettlebell overhead.','After fully extending the body, descend into a lunge position to receive the weights overhead, one leg forward and one leg back. Ensure you drive through with your hips and lock the ketttlebells overhead in one uninterrupted motion.','Return to a standing position, holding the weight overhead, and bring the feet together. Lower the weight to return to the starting position.'], ARRAY['shoulders'], ARRAY['hamstrings','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Kettlebell Swings', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY[]::TEXT[], ARRAY['hamstrings'], ARRAY['calves','glutes','lower back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Long Bar Row', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Position a bar into a landmine or in a corner to keep it from moving. Load an appropriate weight onto your end.','Stand next to the bar, and take a grip with one hand close to the collar. Using your hips and legs, rise to a standing position.','Assume a bent-knee stance with your hips back and your chest up. Your arm should be extended. This will be your starting position.','Pull the weight to your side by retracting the shoulder and flexing the elbow. Do not jerk the weight or cheat during the movement.','After a brief pause, return to the starting position.'], ARRAY['middle back'], ARRAY['biceps','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Medicine Ball Slam', 'medicine ball', true, 'medicine ball', 'beginner', 'pull', 'compound', ARRAY['Start in a standing position with a staggered, athletic stance. Hold a medicine ball in one hand, on the same side as your back leg. This will be your starting position.','Begin by winding the arm, raising the medicine ball above your head. As you do so, extend through the hips, knees, and ankles to load up for the slam.','At peak extension, flex the shoulders, spine, and hips to throw the ball hard into the ground directly in front of you.','Catch the ball on the bounce and continue for the desired number of repetitions.'], ARRAY['abdominals'], ARRAY['lats','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Open Palm Kettlebell Clean', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY['Place one kettlebell between your feet.','Grab the handle with one hand and raise the kettlebell rapidly, let it flip so that the ball of the kettlebell lands in the palm of your hand.','Throw the kettlebell out in front of you and catch the handle with one hand.','Take the kettlebell to the floor and repeat. Make sure to work both arms.'], ARRAY['hamstrings'], ARRAY['forearms','glutes','lower back','quadriceps','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Overhead Kettlebell Squats', 'kettlebells', true, 'kettlebells', 'expert', 'push', 'compound', ARRAY['Clean and press a kettlebell with one arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so. Press the weight overhead by extending through the elbow.This will be your starting position.','Looking straight ahead and keeping a kettlebell locked out above you, flex the knees and hips and lower your torso between your legs, keeping your head and chest up.','Pause at the bottom position for a second before rising back to the top, driving through the heels of your feet.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Side Deadlift', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Stand to the side of a barbell next to its center. Bend your knees and lower your body until you are able to reach the barbell.','Grasp the bar as if you were grabbing a briefcase (palms facing you since the bar is sideways). You may need a wrist wrap if you are using a significant amount of weight. This is your starting position.','Use your legs to help lift the barbell up while exhaling. Your arms should extend fully as bring the barbell up until you are in a standing position.','Slowly bring the barbell back down while inhaling. Tip: Make sure to bend your knees while lowering the weight to avoid any injury from occurring.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the movement.'], ARRAY['quadriceps'], ARRAY['abdominals','calves','glutes','hamstrings','lower back','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Arm Side Laterals', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Pick a dumbbell and place it in one of your hands. Your non lifting hand should be used to grab something steady such as an incline bench press. Lean towards your lifting arm and away from the hand that is gripping the incline bench as this will allow you to keep your balance.','Stand with a straight torso and have the dumbbell by your side at arm''s length with the palm of the hand facing you. This will be your starting position.','While maintaining the torso stationary (no swinging), lift the dumbbell to your side with a slight bend on the elbow and your hand slightly tilted forward as if pouring water in a glass. Continue to go up until you arm is parallel to the floor. Exhale as you execute this movement and pause for a second at the top.','Lower the dumbbell back down slowly to the starting position as you inhale.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the exercise.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One-Legged Cable Kickback', 'cable', true, 'cable', 'intermediate', 'push', 'isolation', ARRAY['Hook a leather ankle cuff to a low cable pulley and then attach the cuff to your ankle.','Face the weight stack from a distance of about two feet, grasping the steel frame for support.','While keeping your knees and hips bent slightly and your abs tight, contract your glutes to slowly kick the working leg back in a semicircular arc as high as it will comfortably go as you breathe out. Tip: At full extension, squeeze your glutes for a second in order to achieve a peak contraction.','Now slowly bring your working leg forward, resisting the pull of the cable until you reach the starting position.','Repeat for the recommended amount of repetitions.','Switch legs and repeat the movement for the other side.'], ARRAY['glutes'], ARRAY['hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One Arm Chin-Up', 'other', true, 'other', 'expert', 'pull', 'compound', ARRAY['For this exercise, start out by placing a towel around a chin up bar.','Grab the chin-up bar with your palm facing you. One hand will be grabbing the chin-up bar and the other will be grabbing the towel.','Bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.v','Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.','Repeat this motion for the prescribed amount of repetitions.','Switch arms and repeat the movement.'], ARRAY['middle back'], ARRAY['biceps','forearms','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One Arm Dumbbell Bench Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Lie down on a flat bench with a dumbbell in one hand on top of your thigh.','By using your thigh to help you get the dumbbell up, clean the dumbbell up so that you can hold it in front of you at shoulder width. Use the hand you are not lifting with to help position the dumbbell over you properly.','Once at shoulder width, rotate your wrist forward so that the palm of your hand is facing away from you. This will be your starting position.','Bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbell at all times. Tip: Use the hand that you are not lifting with to help keep the dumbbell balance as you may struggle a bit at first. Only use your non-lifting hand if it is needed. Otherwise, keep it resting to the side.','As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions of your training program.','Switch arms and repeat the movement.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One Arm Dumbbell Preacher Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Grab a dumbbell with the right arm and place the upper arm on top of the preacher bench or the incline bench. The dumbbell should be held at shoulder length. This will be your starting position.','As you breathe in, slowly lower the dumbbell until your upper arm is extended and the biceps is fully stretched.','As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the dumbbell is at shoulder height. Again, remember that to ensure full contraction you need to bring that small finger higher than the thumb.','Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions.','Switch arms and repeat the movement.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One Arm Floor Press', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Lie down on a flat surface with your back pressing against the floor or an exercise mat. Make sure your knees are bent.','Have a partner hand you the bar on one hand. When starting, your arm should be just about fully extended, similar to the starting position of a barbell bench press. However, this time your grip will be neutral (palms facing your torso).','Make sure the hand you are not using to lift the weight is placed by your side.','Begin the exercise by lowering the barbell until your elbow touches the ground. Make sure to breathe in as this is the eccentric (lowering part of the exercise).','Then start lifting the barbell back up to the original starting position. Remember to breathe out during the concentric (lifting part of the exercise).','Repeat until you have performed your recommended repetitions.','Switch arms and repeat the movement.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One Arm Lat Pulldown', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Select an appropriate weight and adjust the knee pad to help keep you down. Grasp the handle with a pronated grip. This will be your starting position.','Pull the handle down, squeezing your elbow to your side as you flex the elbow.','Pause at the bottom of the motion, and then slowly return the handle to the starting position.','For multiple repetitions, avoid completely returning the weight to keep tension on the muscles being worked.'], ARRAY['lats'], ARRAY['biceps','middle back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One Arm Pronated Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your feet as a pronated grip is required to perform this exercise.','Place your non lifting hand on your bicep for support.','Slowly begin to lower the dumbbell down as you breathe in.','Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).','Repeat until you have performed your set repetitions.','Switch arms and repeat the movement.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One Arm Supinated Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your face as a supinated grip is required to perform this exercise.','Place your non lifting hand on your bicep for support.','Slowly begin to lower the dumbbell down as you breathe in.','Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).','Repeat until you have performed your set repetitions.','Switch arms and repeat the movement.','Switch arms again and repeat the movement.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('One Leg Barbell Squat', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['Start by standing about 2 to 3 feet in front of a flat bench with your back facing the bench. Have a barbell in front of you on the floor. Tip: Your feet should be shoulder width apart from each other.','Bend the knees and use a pronated grip with your hands being wider than shoulder width apart from each other to lift the barbell up until you can rest it on your chest.','Then lift the barbell over your head and rest it on the base of your neck. Move one foot back so that your toe is resting on the flat bench. Your other foot should be stationary in front of you. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. Tip: Make sure your back is straight and chest is out while performing this exercise.','As you inhale, slowly lower your leg until your thigh is parallel to the floor. At this point, your knee should be over your toes. Your chest should be directly above the middle of your thigh.','Leading with the chest and hips and contracting the quadriceps, elevate your leg back to the starting position as you exhale.','Repeat for the recommended amount of repetitions.','Switch legs and repeat the movement.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Open Palm Kettlebell Clean', 'kettlebells', true, 'kettlebells', 'expert', 'pull', 'compound', ARRAY['Place one kettlebell between your feet. Clean the kettlebell by extending through the legs and hips as you raise the kettlebell towards your shoulders.','Release the kettlebell as it comes up, and let it flip so that the ball of the kettlebell lands in the palms of your hands.','Release the kettlebell out in front of you and catch the handle with both hands. Lower the kettlebell to the starting position and repeat.'], ARRAY['hamstrings'], ARRAY['glutes','lower back','quadriceps','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Otis-Up', 'other', true, 'other', 'beginner', 'pull', 'compound', ARRAY['Secure your feet and lay back on the floor. Your knees should be bent. Hold a weight with both hands to your chest. This will be your starting position.','Initiate the movement by flexing the hips and spine to raise your torso up from the ground.','As you move up, press the weight up so that it is above your head at the top of the movement.','Return the weight to your chest as you reverse the sit-up motion, ensuring not to go all the way down to the floor.'], ARRAY['abdominals'], ARRAY['chest','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Overhead Cable Curl', 'cable', true, 'cable', 'intermediate', 'pull', 'isolation', ARRAY['To begin, set a weight that is comfortable on each side of the pulley machine. Note: Make sure that the amount of weight selected is the same on each side.','Now adjust the height of the pulleys on each side and make sure that they are positioned at a height higher than that of your shoulders.','Stand in the middle of both sides and use an underhand grip (palms facing towards the ceiling) to grab each handle. Your arms should be fully extended and parallel to the floor with your feet positioned shoulder width apart from each other. Your body should be evenly aligned the handles. This is the starting position.','While exhaling, slowly squeeze the biceps on each side until your forearms and biceps touch.','While inhaling, move your forearms back to the starting position. Note: Your entire body is stationary during this exercise except for the forearms.','Repeat for the recommended amount of repetitions prescribed in your program.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Overhead Slam', 'medicine ball', true, 'medicine ball', 'beginner', 'pull', 'compound', ARRAY['Hold a medine ball with both hands and stand with your feet at shoulder width. This will be your starting position.','Initiate the countermovement by raising the ball above your head and fully extending your body.','Reverse the motion, slamming the ball into the ground directly in front of you as hard as you can.','Receive the ball with both hands on the bounce and repeat the movement.'], ARRAY['lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Overhead Squat', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['Start out by having a barbell in front of you on the floor. Your feet should be wider than shoulder width apart from each other.','Bend the knees and use a pronated grip (palms facing you) to grab the barbell. Your hands should be at a wider than shoulder width apart from each other before lifting. Once you are positioned, lift the barbell up until you can rest it on your chest.','Move the barbell over and slightly behind your head and make sure your arms are fully extended. Keep your head up at all times and also maintain a straight back. Retract your shoulder blades. This is your starting position.','Slowly lower the weight by bending your knees until your thighs are parallel to the ground while inhaling. Tip: Keep your back straight while performing this exercise to avoid any injuries and your arms should remain extended and over your head at all times.','Now use your feet and legs to help bring the weight back up to the starting position while exhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['abdominals','calves','glutes','hamstrings','lower back','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Pallof Press', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Connect a standard handle to a tower, and—if possible—position the cable to shoulder height. If not, a low pulley will suffice.','With your side to the cable, grab the handle with both hands and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable.','With your feet positioned hip-width apart and knees slightly bent, hold the cable to the middle of your chest. This will be your starting position.','Press the cable away from your chest, fully extending both arms. You core should be tight and engaged.','Hold the repetition for several seconds before returning to the starting position.','At the conclusion of the set, repeat facing the other direction.'], ARRAY['abdominals'], ARRAY['chest','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Pallof Press With Rotation', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Connect a standard handle to a tower, and position the cable to shoulder height.','With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Align outstretched arm with cable.','With your feet positioned hip-width apart, pull the cable into your chest and grab the handle with your other hand. Both hands should be on the handle at this time.','Facing forward, press the cable away from your chest. You core should be tight and engaged.','Keeping your hips straight, twist your torso away from the pulley until you get a full quarter rotation.','Maintain your rigid stance and straight arms. Return to the neutral position in a slow and controlled manner. Your arms should be extended in front of you.','With the side tension still engaging your core, bring your hands to your chest and immediately press outward to a fully extended position. This constitutes one rep.','Repeat to failure.','Then, reposition and repeat the same series of movements on the opposite side.'], ARRAY['abdominals'], ARRAY['chest','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Palms-Down Dumbbell Wrist Curl Over A Bench', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing two dumbbells on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab both of the dumbbells with a pronated grip (palms facing down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Palms-Down Wrist Curl Over A Bench', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing a barbell on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab the barbell with a pronated grip (palms down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Palms-Up Barbell Wrist Curl Over A Bench', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing a barbell on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab the barbell with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Palms-Up Dumbbell Wrist Curl Over A Bench', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing two dumbbells on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab both of the dumbbells with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Parallel Bar Dip', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Stand between a set of parallel bars. Place a hand on each bar, and then take a small jump to help you get into the starting position with your arms locked out.','Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.','Reverse the motion by extending the elbow, pushing yourself back up into the starting position.','Repeat for the desired number of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Physioball Hip Bridge', 'exercise ball', true, 'exercise ball', 'beginner', 'push', 'compound', ARRAY['Lay on a ball so that your upper back is on the ball with your hips unsupported. Both feet should be flat on the floor, hip width apart or wider. This will be your starting position.','Begin by extending the hips using your glutes and hamstrings, raising your hips upward as you bridge.','Pause at the top of the motion and return to the starting position.'], ARRAY['glutes'], ARRAY['hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Pin Presses', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Pin presses remove the eccentric phase of the bench press, developing starting strength. They also allow you to train a desired range of motion.','The bench should be set up in a power rack. Set the pins to the desired point in your range of motion, whether it just be lockout or an inch off of your chest. The bar should be moved to the pins and prepared for lifting.','Begin by lying on the bench, with the bar directly above the contact point during your regular bench. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement.','You can take a standard bench grip, or shoulder width to focus on the triceps. The bar, wrist, and elbow should stay in line at all times. Focus on squeezing the bar and trying to pull it apart.','Drive the bar up with as much force as possible. The elbows should be tucked in until lockout.','Return the bar to the pins, pausing before beginning the next repetition.'], ARRAY['triceps'], ARRAY['chest','forearms','lats','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Plank', 'body only', true, 'body only', 'beginner', 'static', 'isolation', ARRAY['Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder.','Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Plate Pinch', 'other', true, 'other', 'intermediate', 'static', 'isolation', ARRAY['Grab two wide-rimmed plates and put them together with the smooth sides facing outward','Use your fingers to grip the outside part of the plate and your thumb for the other side thus holding both plates together. This is the starting position.','Squeeze the plate with your fingers and thumb. Hold this position for as long as you can.','Repeat for the recommended amount of sets prescribed in your program.','Switch arms and repeat the movements.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Plate Twist', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['Lie down on the floor or an exercise mat with your legs fully extended and your upper body upright. Grab the plate by its sides with both hands out in front of your abdominals with your arms slightly bent.','Slowly cross your legs near your ankles and lift them up off the ground. Your knees should also be bent slightly. Note: Move your upper body back slightly to help keep you balanced turning this exercise. This is the starting position.','Move the plate to the left side and touch the floor with it. Breathe out as you perform that movement.','Come back to the starting position as you breathe in and then repeat the movement but this time to the right side of the body. Tip: Use a slow controlled movement at all times. Jerking motions can injure the back.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Platform Hamstring Slides', 'other', true, 'other', 'beginner', 'pull', 'isolation', ARRAY['For this movement a wooden floor or similar is needed. Lay on your back with your legs extended. Place a gym towel or a light weight underneath your heel. This will be your starting position.','Begin the movement by flexing the knee, keeping your other leg straight.','Continue bringing the heel closer to you, sliding it on the floor.','At full knee flexion, reverse the movement to return to the starting position.'], ARRAY['hamstrings'], ARRAY['glutes'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Plie Dumbbell Squat', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Hold a dumbbell at the base with both hands and stand straight up. Move your legs so that they are wider than shoulder width apart from each other with your knees slightly bent.','Your toes should be facing out. Note: Your arms should be stationary while performing the exercise. This is the starting position.','Slowly bend the knees and lower your legs until your thighs are parallel to the floor. Make sure to inhale as this is the eccentric part of the exercise.','Press mainly with the heel of the foot to bring the body back to the starting position while exhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['abdominals','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Plyo Kettlebell Pushups', 'kettlebells', true, 'kettlebells', 'expert', 'push', 'compound', ARRAY['Place a kettlebell on the floor. Place yourself in a pushup position, on your toes with one hand on the ground and one hand holding the kettlebell, with your elbows extended. This will be your starting position.','Begin by lowering yourself as low as you can, keeping your back straight.','Quickly and forcefully reverse direction, pushing yourself up to the other side of the kettlebell, switching hands as you do so. Continue the movement by descending and repeating the movement back and forth.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Plyo Push-up', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Move into a prone position on the floor, supporting your weight on your hands and toes.','Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.','Descend by flexing at the elbow, lowering your chest towards the ground.','At the bottom, reverse the motion by pushing yourself up through elbow extension as quickly as possible. Attempt to push your upper body up until your hands leave the ground.','Return to the starting position and repeat the exercise.','For added difficulty, add claps into the movement while you are air borne.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Power Clean', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Stand with your feet slightly wider than shoulder width apart and toes pointing out slightly.','Squat down and grasp bar with a closed, pronated grip. Your hands should be slightly wider than shoulder width apart outside knees with elbows fully extended.','Place the bar about 1 inch in front of your shins and over the balls of your feet.','Your back should be flat or slightly arched, your chest held up and out and your shoulder blades should be retracted.','Keep your head in a neutral position (in line with vertebral column and not tilted or rotated) with your eyes focused straight ahead. Inhale during this phase.','Lift the bar from the floor by forcefully extending the hips and the knees as you exhale. Tip: The upper torso should maintain the same angle. Do not bend at the waist yet and do not let the hips rise before the shoulders (this would have the effect of pushing the glutes in the air and stretching the hamstrings.','Keep elbows fully extended with the head in a neutral position and the shoulders over the bar.','As the bar raises keep it as close to the shins as possible.','As the bar passes the knees, thrust your hips forward and slightly bend the knees to avoid locking them. Tip: At this point your thighs should be against the bar.','Keep the back flat or slightly arched, elbows fully extended and your head neutral. Tip: You will hold your breath until the next phase.','Inhale and then forcefully and quickly extend your hips and knees and stand on your toes.','Keep the bar as close to your body as possible. Tip: Your back should be flat with the elbows pointed out to the sides and your head in a neutral position. Also, keep your shoulders over the bar and arms straight as long as possible.','When your lower body joints are fully extended, shrug the shoulders upward rapidly without letting the elbows flex yet. Exhale during this portion of the movement.','As the shoulders reach their highest elevation flex your elbows to begin pulling your body under the bar.','Continue to pull the arms as high and as long as possible. Tip: Due to the explosive nature of this phase, your torso will be erect or with an arched back, your head will be tilted back slightly and your feet may lose contact with the floor.','After the lower body has fully extended and the bar reaches near maximal height, pull your body under the bar and rotate the arms around and under the bar.','Simultaneously, flex the hips and knees into a quarter squat position.','Once the arms are under the bar, inhale and then lift your elbows to position the upper arms parallel to the floor. Rack the bar across the front of your collar bones and front shoulder muscles.','Catch the bar with an erect and tight torso, a neutral head position and flat feet. Exhale during this movement.','Stand up by extending the hips and knees to a fully erect position.','Lower the bar by gradually reducing the muscular tension of the arms to allow a controlled descent of the bar to the thighs. Inhale during this movement.','Simultaneously flex the hips and knees to cushion the impact of the bar on the thighs.','Squat down with the elbows fully extended until the bar touches the floor.','Start over at Phase 1 and repeat for the recommended amount of repetitions.'], ARRAY['hamstrings'], ARRAY['calves','forearms','glutes','lower back','middle back','quadriceps','shoulders','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Power Clean from Blocks', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['With a barbell on boxes of the desired height, take a grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. As the bar approaches the mid-thigh position, begin extending through the hips.','In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight. At the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.','As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, pull yourself under the bar far enough that it can be racked onto the shoulders, rotating your elbows under the bar as you do so. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position, and complete the repetition by returning the weight to the boxes.'], ARRAY['hamstrings'], ARRAY['quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Power Jerk', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible.','Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.','At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible. In the brief moment the feet are not actively driving against the platform, the athletes effort to push the bar up will drive them down. The feet should be moved to a slightly wider stance, with the knees partially bent.','Receive the bar with the arms locked out overhead.','Return to a standing position.'], ARRAY['quadriceps'], ARRAY['abdominals','calves','glutes','hamstrings','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Power Partials', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.','The palms of the hands should be facing your torso. Your feet should be about shoulder width apart. This will be your starting position.','Keeping your arms straight and the torso stationary, lift the weights out to your sides until they are about shoulder level height while exhaling.','Feel the contraction for a second and begin to lower the weights back down to the starting position while inhaling. Tip: Keep the palms facing down with the little finger slightly higher while lifting and lowering the weights as it will concentrate the stress on your shoulders mainly.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Power Snatch', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Begin with a loaded barbell on the floor. The bar should be close to or touching the shins, and a wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.','Begin the first pull by driving through the front of the heels, raising the bar from the ground. The back angle should stay the same until the bar passes the knees.','Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, a slightly wider position, pull yourself below the bar as you elevate the bar overhead. The bar should be received in a partial squat. Continue raising the bar to the overhead position, receiving the bar locked out overhead.','Return to a standing position with the weight over head.'], ARRAY['hamstrings'], ARRAY['calves','glutes','lower back','quadriceps','shoulders','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Power Snatch from Blocks', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin with a loaded barbell on boxes or stands of the desired height. A wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar, with the elbows pointed out. This will be the starting position.','Begin the first pull by driving through the front of the heels, raising the bar from the boxes.','Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. The feet should move to just outside the hips, turned out as necessary. Receive the bar above a full squat and with the arms fully extended overhead.','Keeping the bar aligned over the front of the heels, your head and chest up, drive through heels of the feet to move to a standing position. Carefully return the weight to the boxes.'], ARRAY['quadriceps'], ARRAY['calves','forearms','glutes','hamstrings','lower back','shoulders','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Power Stairs', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['In the power stairs, implements are moved up a staircase. For training purposes, these can be performed with a tire or box.','Begin by taking the implement with both hands. Set your feet wide, with your head and chest up. Drive through the ground with your heels, extending your knees and hips to raise the weight from the ground.','As you lean back, attempt to swing the weight onto the stairs, which are usually around 16-18 high. You can use your legs to help push the weight onto the stair.','Repeat for 3-5 repetitions, and continue with a heavier weight, moving as fast as possible.'], ARRAY['hamstrings'], ARRAY['adductors','calves','glutes','lower back','quadriceps','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Preacher Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['To perform this movement you will need a preacher bench and an E-Z bar. Grab the E-Z curl bar at the close inner handle (either have someone hand you the bar which is preferable or grab the bar from the front bar rest provided by most preacher benches). The palm of your hands should be facing forward and they should be slightly tilted inwards due to the shape of the bar.','With the upper arms positioned against the preacher bench pad and the chest against it, hold the E-Z Curl Bar at shoulder length. This will be your starting position.','As you breathe in, slowly lower the bar until your upper arm is extended and the biceps is fully stretched.','As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the bar is at shoulder height. Squeeze the biceps hard and hold this position for a second.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Preacher Hammer Dumbbell Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Place the upper part of both arms on top of the preacher bench as you hold a dumbbell in each hand with the palms facing each other (neutral grip).','As you breathe in, slowly lower the dumbbells until your upper arm is extended and the biceps is fully stretched.','As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the dumbbells are at shoulder height.','Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Press Sit-Up', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['To begin, lie down on a bench with a barbell resting on your chest. Position your legs so they are secure on the extension of the abdominal bench. This is the starting position.','While inhaling, tighten your abdominals and glutes. Simultaneously curl your torso as you do when performing a sit-up and press the barbell to an overhead position while exhaling. Tip: Use your arms to push the barbell out as you perform this exercise while still focusing on the abdominal muscles.','Lower your upper body back down to the starting position while bringing the barbell back down to your torso. Remember to breathe in while lowering the body.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY['chest','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Prone Manual Hamstring', 'body only', true, 'body only', 'beginner', 'static', 'isolation', ARRAY['You will need a partner for this exercise. Lay face down with your legs straight. Your assistant will place their hand on your heel.','To begin, flex the knee to curl your leg up. Your partner should provide resistance, starting light and increasing the pressure as the movement is completed. Communicate with your partner to monitor appropriate resistance levels.','Pause at the top, returning the leg to the starting position as your partner provides resistance going the other direction.'], ARRAY['hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Prowler Sprint', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Place your sled on an appropriate surface, loaded to a suitable weight. The sled should provide enough resistance to require effort, but not so heavy that you are significantly slowed down.','You may use the upright or the low handles for this exercise. Place your hands on the handles with your arms extended, leaning into the implement.','With good posture, drive through the ground with alternating, short steps. Move as fast as you can for a short distance.'], ARRAY['hamstrings'], ARRAY['calves','chest','glutes','quadriceps','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Pull Through', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Begin standing a few feet in front of a low pulley with a rope or handle attached. Face away from the machine, straddling the cable, with your feet set wide apart.','Begin the movement by reaching through your legs as far as possible, bending at the hips. Keep your knees slightly bent. Keeping your arms straight, extend through the hip to stand straight up. Avoid pulling upward through the shoulders; all of the motion should originate through the hips.'], ARRAY['glutes'], ARRAY['hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Pullups', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Grab the pull-up bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.','As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.','Repeat this motion for the prescribed amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','middle back'], ARRAY['Full dead hang at bottom, chin over bar at top','Initiate by pulling shoulder blades down','Drive elbows toward your hips','Control the descent, 2 seconds down','If you cant do them, use band assistance'], ARRAY['Half reps, not going to full hang','Kipping or swinging','Not getting chin over bar','Going too fast without control'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Push-Up Wide', 'body only', true, 'body only', 'beginner', NULL, 'compound', ARRAY['With your hands wide apart, support your body on your toes and hands in a plank position. Your elbows should be extended and your body straight. Do not allow your hips to sag. This will be your starting position.','To begin, allow the elbows to flex, lowering your chest to the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position by extending the elbows. Exhale as you perform this step.','After pausing at the contracted position, repeat the movement for the prescribed amount of repetitions.'], ARRAY['chest'], ARRAY['abdominals','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Push-Ups - Close Triceps Position', 'body only', true, 'body only', 'intermediate', 'push', 'compound', ARRAY['Lie on the floor face down and place your hands closer than shoulder width for a close hand position. Make sure that you are holding your torso up at arms'' length.','Lower yourself until your chest almost touches the floor as you inhale.','Using your triceps and some of your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Push-Ups With Feet Elevated', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.','Place your toes on top of a flat bench. This will allow your body to be elevated. Note: The higher the elevation of the flat bench, the higher the resistance of the exercise is.','Lower yourself until your chest almost touches the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Push-Ups With Feet On An Exercise Ball', 'exercise ball', true, 'exercise ball', 'intermediate', 'push', 'compound', ARRAY['Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.','Place your toes on top of an exercise ball. This will allow your body to be elevated.','Lower yourself until your chest almost touches the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

